import{_ as t,c as r,o as i,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const k=JSON.parse('{"title":"v1.1.50：shell.env Hook、Skills 路径扩展、内存泄漏修复","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.50.md","filePath":"changelog/v1.1.50.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.50.md"};function n(s,l,d,h,c,p){return i(),r("div",null,[...l[0]||(l[0]=[a('<h1 id="v1-1-50-shell-env-hook、skills-路径扩展、内存泄漏修复" tabindex="-1">v1.1.50：shell.env Hook、Skills 路径扩展、内存泄漏修复 <a class="header-anchor" href="#v1-1-50-shell-env-hook、skills-路径扩展、内存泄漏修复" aria-label="Permalink to “v1.1.50：shell.env Hook、Skills 路径扩展、内存泄漏修复”">​</a></h1><p><strong>发布日期</strong>：2026年02月04日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新新增了 shell.env Hook 让插件可以注入环境变量，Skills 系统支持从 <code>.agents/skills</code> 目录读取，修复了 AbortController 内存泄漏，并大幅改进桌面端体验。</p><hr><h2 id="新功能-shell-env-hook" tabindex="-1">新功能：shell.env Hook <a class="header-anchor" href="#新功能-shell-env-hook" aria-label="Permalink to “新功能：shell.env Hook”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>新增 <code>shell.env</code> 插件钩子，可以在所有 shell 执行环境中注入自定义环境变量。</p><h3 id="shell-env-hook-是什么" tabindex="-1">shell.env Hook 是什么？ <a class="header-anchor" href="#shell-env-hook-是什么" aria-label="Permalink to “shell.env Hook 是什么？”">​</a></h3><p>这是一个插件事件钩子，让你可以通过插件向 AI 工具调用和用户终端注入环境变量。比如你可以注入 API Key、项目路径等信息，让 AI 在执行命令时自动获取这些变量。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>在项目中创建插件文件：</p>',13),e("div",{class:"language-js"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"js"),e("pre",null,[e("code",{"v-pre":""},`// .opencode/plugins/inject-env.js
export const InjectEnvPlugin = async () => {
  return {
    "shell.env": async (input, output) => {
      output.env.MY_API_KEY = "secret"
      output.env.PROJECT_ROOT = input.cwd
    },
  }
}`)])],-1),a('<p>注入的环境变量对 AI 工具执行和用户终端都生效。</p><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/12b-plugins-advanced.html">插件进阶</a></p><hr><h2 id="新功能-skills-支持-agents-skills-目录" tabindex="-1">新功能：Skills 支持 .agents/skills 目录 <a class="header-anchor" href="#新功能-skills-支持-agents-skills-目录" aria-label="Permalink to “新功能：Skills 支持 .agents/skills 目录”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>Skills 系统现在支持从 <code>.agents/skills</code> 目录读取 SKILL.md 文件，兼容更多 Agent 框架的目录结构。</p><h3 id="有什么用" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用" aria-label="Permalink to “有什么用？”">​</a></h3><p>如果你使用其他 Agent 框架（如 Claude Code），可以把 Skills 放在 <code>.agents/skills/</code> 目录下，OpenCode 也能识别。</p><h3 id="完整搜索路径" tabindex="-1">完整搜索路径 <a class="header-anchor" href="#完整搜索路径" aria-label="Permalink to “完整搜索路径”">​</a></h3><table tabindex="0"><thead><tr><th>级别</th><th>路径</th></tr></thead><tbody><tr><td>项目级 OpenCode 原生</td><td><code>.opencode/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>全局 OpenCode 原生</td><td><code>~/.config/opencode/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>项目级 Claude 兼容</td><td><code>.claude/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>全局 Claude 兼容</td><td><code>~/.claude/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>项目级 Agent 兼容</td><td><code>.agents/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>全局 Agent 兼容</td><td><code>~/.agents/skills/&lt;name&gt;/SKILL.md</code></td></tr></tbody></table><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/03a-skills-basics.html">Skill 基��</a></p><hr><h2 id="新功能-agent-自定义主题色" tabindex="-1">新功能：Agent 自定义主题色 <a class="header-anchor" href="#新功能-agent-自定义主题色" aria-label="Permalink to “新功能：Agent 自定义主题色”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在可以在自定义 Agent 时设置主题颜色，让不同 Agent 在界面上更容易区分。</p><hr><h2 id="问题修复-abortcontroller-内存泄漏" tabindex="-1">问题修复：AbortController 内存泄漏 <a class="header-anchor" href="#问题修复-abortcontroller-内存泄漏" aria-label="Permalink to “问题修复：AbortController 内存泄漏”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>长时间使用 OpenCode 时，AbortController 的闭包会导致内存泄漏，占用越来越多内存。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了 AbortController 闭包的内存泄漏问题，长时间使用不再出现内存持续增长。</p><hr><h2 id="问题修复-插件重复安装" tabindex="-1">问题修复：插件重复安装 <a class="header-anchor" href="#问题修复-插件重复安装" aria-label="Permalink to “问题修复：插件重复安装”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>每次启动 OpenCode 时，插件都会被重新安装，即使已经安装过了。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>插件安装状态正确缓存，不再重复安装。</p><hr><h2 id="改进-桌面端体验" tabindex="-1">改进：桌面端体验 <a class="header-anchor" href="#改进-桌面端体验" aria-label="Permalink to “改进：桌面端体验”">​</a></h2><h3 id="会话标签恢复" tabindex="-1">会话标签恢复 <a class="header-anchor" href="#会话标签恢复" aria-label="Permalink to “会话标签恢复”">​</a></h3><p>重启桌面应用后，之前打开的会话标签页会自动恢复。</p><h3 id="命令面板搜索" tabindex="-1">命令面板搜索 <a class="header-anchor" href="#命令面板搜索" aria-label="Permalink to “命令面板搜索”">​</a></h3><p>会话搜索功能移到了命令面板中，操作更统一。</p><h3 id="空提示词提交" tabindex="-1">空提示词提交 <a class="header-anchor" href="#空提示词提交" aria-label="Permalink to “空提示词提交”">​</a></h3><p>桌面端现在允许在有 review comments 时提交空提示词。</p><h3 id="项目编辑图标" tabindex="-1">项目编辑图标 <a class="header-anchor" href="#项目编辑图标" aria-label="Permalink to “项目编辑图标”">​</a></h3><p>编辑项目对话框的图标现在在悬停时才显示，界面更简洁。</p><hr><h2 id="其他改进" tabindex="-1">其他改进 <a class="header-anchor" href="#其他改进" aria-label="Permalink to “其他改进”">​</a></h2><ul><li>TUI 新增 <code>--thinking</code> 标志，可在 run 命令中显示推理过程</li><li>TUI 剪贴板在 OSC52 失败后自动回退到原生剪贴板</li><li>CLI <code>run</code> 命令改为非交互模式</li><li>Gemini schema 验证支持嵌套数组和非对象类型</li><li>Cloudflare AI Gateway 改用官方 ai-gateway-provider 包</li><li>排除 k2p5 模型的推理变体</li><li>Provider 配置的 headers 现在正确应用到 fetch 请求</li></ul><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>遇到内存泄漏问题</td><td>✅ 强烈推荐</td></tr><tr><td>使用插件系统</td><td>✅ 推荐升级</td></tr><tr><td>桌面端用户</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',44),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Prevent memory leaks from AbortController closures (@MaxLeiter)</li><li>Revert addition of Trinity model system prompt support</li><li>Add Trinity model system prompt support (@mariamjabara)</li><li>Add shell.env hook for manipulating environment in tools and shell (@tylergannon)</li><li>Use official ai-gateway-provider package for Cloudflare AI Gateway (@elithrar)</li><li>Allow theme colors in agent customization (@IdrisGit)</li><li>Add support for reading skills from .agents/skills directories</li><li>Provider headers from config not applied to fetch requests (@cloudyan)</li><li>Ensure MCP tools are sanitized</li><li>Add .slnx to C#/F# LSP root detection (@workedbeforepush)</li><li>Improve skills system with better prompting, fix permission requests after skill invocation, and ensure agents can locate scripts and resources</li><li>Exclude k2p5 from reasoning variants (@neavo)</li><li>Handle nested array items for Gemini schema validation (@mugnimaestra)</li><li>Plugins are always reinstalled (@neriousy)</li><li>Strip properties and required fields from non-object types in Gemini schema (@ChickenBreast-ky)</li><li>Make CLI run command non-interactive</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add --thinking flag to show reasoning blocks in run command</li><li>Always fall back to native clipboard after OSC52 (@MartinWie)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Faster end-to-end tests (@neriousy)</li><li>Update command palette placeholder text</li><li>Model selector truncating too soon</li><li>Improve spacing in application UI</li><li>Allow empty prompt with review comments in desktop (@dbpolito)</li><li>Fixed terminal serialization bug in app</li><li>Don&#39;t force mount tooltips in the app</li><li>Restore previously opened session tabs on app restart (@ProdigyRahul)</li><li>Edit project dialog icon now shows on hover (@ProdigyRahul)</li><li>Move session search to command palette</li><li>Fix custom providers overflow in app (@DNGriffin)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const b=t(o,[["render",n]]);export{k as __pageData,b as default};
